// CLX Voice Result Webhook v1 — Normalize Vapi payload
// Extracts the fields we care about from Vapi's end-of-call-report.
// Silently ignores other message types (e.g., 'status-update') so that
// in-flight events don't pollute voice_call_log.

const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const msg = body.message || body;

const type = msg.type || body.type || null;
if (type && type !== 'end-of-call-report') {
  return { json: { _skip: true, skip_reason: 'non_terminal_message_type', type } };
}

const call = msg.call || body.call || {};
const endedReason = msg.endedReason || call.endedReason || null;
const duration = msg.durationSeconds || msg.duration || call.duration || null;
const cost = msg.cost || call.cost || null;
const recording = msg.recordingUrl || call.recordingUrl || null;
const transcript = msg.transcript || call.transcript || null;
const vapi_call_id = msg.callId || call.id || body.callId || null;

if (!vapi_call_id) {
  return { json: { _skip: true, skip_reason: 'missing_vapi_call_id' } };
}

// Crude outcome classification. Real taxonomy: connected, no-answer,
// voicemail, hangup-short, blocked. Vapi's endedReason is the best
// proxy; anything with meaningful duration + transcript is 'connected'.
let outcome = 'unknown';
if (endedReason === 'customer-did-not-answer' || endedReason === 'assistant-did-not-answer') outcome = 'no_answer';
else if (endedReason === 'voicemail') outcome = 'voicemail';
else if ((duration || 0) < 10) outcome = 'hangup_short';
else if (transcript && transcript.length > 0) outcome = 'connected';
else outcome = 'disconnected';

return {
  json: {
    vapi_call_id,
    outcome,
    duration_sec: duration ? Math.round(Number(duration)) : null,
    cost_usd: cost ? Number(cost) : null,
    recording_url: recording,
    transcript,
    ended_reason: endedReason
  }
};

// CLX Voice Result Webhook v1 — Correlate + merge
// Vapi sends result long after the outbound call row was inserted by
// clx-voice-outreach-v1. We look up the voice_call_log row by
// vapi_call_id to recover lead_id / client_id, then produce both:
//   (a) an UPDATE body for voice_call_log
//   (b) a lead-update body for rpc/update_lead (bump status if connected)
// If no row is found, log a correlation failure and skip downstream.

const norm = $('Normalize Payload').first().json;
const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;

if (!row || !row.id) {
  return { json: { _skip: true, skip_reason: 'voice_call_log_row_not_found', vapi_call_id: norm.vapi_call_id } };
}

// Only flip lead_status to Replied on a real connected conversation —
// voicemails and hangups do not imply consent.
const connected = norm.outcome === 'connected';

const voice_update_body = {
  call_outcome: norm.outcome,
  duration_sec: norm.duration_sec,
  transcript: norm.transcript,
  recording_url: norm.recording_url,
  cost_usd: norm.cost_usd,
  metadata: { ended_reason: norm.ended_reason, updated_at: new Date().toISOString() }
};

const lead_update_body = {
  p_lead_id: row.lead_id,
  p_fields: Object.assign(
    {
      last_channel_attempted: 'voice',
      last_channel_attempted_at: new Date().toISOString()
    },
    connected ? { lead_status: 'Replied' } : {}
  )
};

return {
  json: {
    voice_call_log_id: row.id,
    lead_id: row.lead_id,
    client_id: row.client_id,
    vapi_call_id: norm.vapi_call_id,
    voice_update_body: JSON.stringify(voice_update_body),
    lead_update_body: JSON.stringify(lead_update_body),
    connected,
    outcome: norm.outcome
  }
};
